class FreqStack {
    Map<Integer, Integer> frequencyMap;
    Map<Integer, Stack<Integer>> stackMap;
    int maxFrequency;

    public FreqStack() {
        frequencyMap = new HashMap<>();
        stackMap = new HashMap<>();
        maxFrequency = 0;
    }

    public void push(int val) {
        int frequency = frequencyMap.getOrDefault(val, 0) + 1;
        frequencyMap.put(val, frequency);
        if (frequency > maxFrequency) {
            maxFrequency = frequency;
        }
        stackMap.computeIfAbsent(frequency, k -> new Stack<>()).push(val);
    }

    public int pop() {
        int result = stackMap.get(maxFrequency).pop();
        frequencyMap.put(result, frequencyMap.get(result) - 1);
        if (stackMap.get(maxFrequency).isEmpty()) {
            maxFrequency--;
        }
        return result;
    }
}
